<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function iinqError(m){$('.isi_warning_delete').text(m||'Incoming Inspection gagal diproses.');$('.error_data_delete').fadeIn();}
function iinqFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),material_code:$('#filter_material').val(),plant_id:$('#filter_plant').val(),storage_location_id:$('#filter_storage_location').val(),storage_bin_id:$('#filter_storage_bin').val(),stock_type:$('#filter_stock_type').val(),inspection_status:$('#filter_inspection_status').val(),keyword:$('#filter_keyword').val()};}
function iinqExcelUrl(){return '<?=base_admin();?>modul/incoming_inspection/incoming_inspection_action.php?act=excel&'+$.param(iinqFilters());}
function iinqInitSelect(){if(!$.fn.select2)return;$('#filter_plant,#filter_storage_location,#filter_storage_bin,#filter_stock_type,#filter_inspection_status,#ud_code').select2({width:'100%',allowClear:true});$('#filter_material').select2({width:'100%',allowClear:true,placeholder:'Cari material...',minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/incoming_inspection/incoming_inspection_action.php?act=material_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function resultRow(){return '<tr><td><input name="characteristic_no[]" class="form-control input-sm"></td><td><input name="characteristic_name[]" class="form-control input-sm"></td><td><input name="specification[]" class="form-control input-sm"></td><td><input name="sample_qty_result[]" class="form-control input-sm text-right" value="0"></td><td><input name="result_value[]" class="form-control input-sm"></td><td><select name="result_status[]" class="form-control input-sm"><option value="PASS">PASS</option><option value="FAIL">FAIL</option><option value="INFO">INFO</option></select></td><td><input name="defect_code[]" class="form-control input-sm"></td><td><input name="defect_qty[]" class="form-control input-sm text-right" value="0"></td><td><input name="remarks_result[]" class="form-control input-sm"></td><td><button type="button" class="btn btn-danger btn-xs btn-remove-result"><i class="fa fa-trash"></i></button></td></tr>';}
$(function(){
  if($.fn.datepicker){$('.iinq-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}
  iinqInitSelect();
  var dt=$('#dtb_incoming_inspection').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:'Export Data',buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[5],className:'text-right'},{width:'42px',targets:0},{width:'145px',targets:1}],ajax:{url:'<?=base_admin();?>modul/incoming_inspection/incoming_inspection_data.php',type:'post',data:function(d){$.extend(d,iinqFilters());},error:function(xhr){console.log(xhr.responseText);iinqError('Data Incoming Inspection gagal dimuat.');}}});
  $('#btn_filter_iinq').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_excel_iinq,#btn_excel_iinq_top').click(function(){window.location=iinqExcelUrl();});
  $('#btn_reset_iinq').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_keyword').val('');$('#filter_material').val(null).trigger('change');$('#filter_plant,#filter_storage_location,#filter_storage_bin,#filter_stock_type,#filter_inspection_status').val('').trigger('change');dt.draw();});
  $(document).on('click','.btn-iinq-source-detail',function(){$.post('<?=base_admin();?>modul/incoming_inspection/incoming_inspection_action.php?act=source_detail',{stock_layer_id:$(this).data('layer-id')},function(html){$('#iinq_detail_body').html(html);$('#modal_iinq_detail').modal('show');}).fail(function(){iinqError('Detail source gagal dibuka.');});});
  $(document).on('click','.btn-iinq-create-lot',function(){var layer=$(this).data('layer-id');Swal.fire({title:'Create inspection lot?',text:'Inspection lot akan dibuat dari stock layer incoming ini.',icon:'question',showCancelButton:true,confirmButtonText:'Create Lot'}).then(function(r){if(!r.isConfirmed)return;$.post('<?=base_admin();?>modul/incoming_inspection/incoming_inspection_action.php?act=create_lot',{stock_layer_id:layer},function(res){if(res.status==='good'){dt.draw(false);Swal.fire('Success','Inspection lot '+res.lot_no+' siap diproses.','success');}else iinqError(res.error_message);},'json').fail(function(xhr){iinqError(xhr.responseText);});});});
  $(document).on('click','.btn-iinq-lot-detail',function(){$.post('<?=base_admin();?>modul/inspection_lot/inspection_lot_action.php?act=detail',{id:$(this).data('id')},function(html){$('#iinq_lot_detail_body').html(html);$('#modal_iinq_lot_detail').modal('show');}).fail(function(){iinqError('Detail lot gagal dibuka.');});});
  $(document).on('click','.btn-iinq-result',function(){$.post('<?=base_admin();?>modul/inspection_lot/inspection_lot_action.php?act=result_form',{id:$(this).data('id')},function(html){$('#iinq_result_body').html(html);$('#modal_iinq_result').modal('show');}).fail(function(){iinqError('Form result gagal dibuka.');});});
  $(document).on('click','#btn_add_result_row',function(){$('#tbl_ilot_result tbody').append(resultRow());});$(document).on('click','.btn-remove-result',function(){$(this).closest('tr').remove();});
  $('#btn_save_iinq_result').click(function(){var btn=$(this);btn.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> Saving...');$.ajax({url:'<?=base_admin();?>modul/inspection_lot/inspection_lot_action.php?act=record_result',type:'POST',data:$('#form_ilot_result').serialize(),dataType:'json',success:function(res){btn.prop('disabled',false).html('<i class="fa fa-check-square-o"></i> Save Result');if(res.status==='good'){$('#modal_iinq_result').modal('hide');dt.draw(false);Swal.fire('Success','Incoming inspection result tersimpan.','success');}else iinqError(res.error_message);},error:function(xhr){btn.prop('disabled',false).html('<i class="fa fa-check-square-o"></i> Save Result');iinqError(xhr.responseText);}});});
  $(document).on('click','.btn-iinq-ud',function(){$.post('<?=base_admin();?>modul/inspection_lot/inspection_lot_action.php?act=ud_form',{id:$(this).data('id')},function(html){$('#iinq_ud_body').html(html);iinqInitSelect();$('#modal_iinq_ud').modal('show');}).fail(function(){iinqError('Form UD gagal dibuka.');});});
  $('#btn_save_iinq_ud').click(function(){Swal.fire({title:'Post usage decision?',text:'UD akan memfinalisasi incoming inspection lot.',icon:'question',showCancelButton:true,confirmButtonText:'Post UD'}).then(function(r){if(!r.isConfirmed)return;$.ajax({url:'<?=base_admin();?>modul/inspection_lot/inspection_lot_action.php?act=usage_decision',type:'POST',data:$('#form_ilot_ud').serialize(),dataType:'json',success:function(res){if(res.status==='good'){$('#modal_iinq_ud').modal('hide');dt.draw(false);Swal.fire('Success','Usage decision berhasil diposting.','success');}else iinqError(res.error_message);},error:function(xhr){iinqError(xhr.responseText);}});});});
  $('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
